+#[inline]
+fn gf256_mul_table(coeff: u8) -> [u8; 256] {
+    let mut table = [0_u8; 256];
+    for (byte, product) in table.iter_mut().enumerate() {
+        *product = gf256_mul_byte(coeff, byte as u8);
+    }
+    table
+}
